struct ImmediateTask {
    struct promise_type {
        ImmediateTask get_return_object() { return {}; }
        std::suspend_never initial_suspend() { return {}; }
        std::suspend_never final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() {}
    };
};

struct ReadyAwaiter {
    bool await_ready() const noexcept { return true; }
    void await_suspend(std::coroutine_handle<>) const noexcept {}
    void await_resume() const noexcept {}
};

ImmediateTask example() {
    std::cout << "قبل الانتظار\n";
    co_await ReadyAwaiter{};
    std::cout << "بعد الانتظار\n";
}

int main() {
    example();
}

#include <coroutine>
#include <iostream>

struct SuspendedTask {
    struct promise_type {
        SuspendedTask get_return_object() { return {}; }
        std::suspend_always initial_suspend() { return {}; }
        std::suspend_never final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() {}
    };
};

struct PauseAwaiter {
    bool await_ready() const noexcept { return false; }
    void await_suspend(std::coroutine_handle<> h) const noexcept {
        // نستأنف فورًا في هذا المثال البسيط
        h.resume();
    }
    void await_resume() const noexcept {}
};

SuspendedTask run() {
    std::cout << "خطوة 1\n";
    co_await PauseAwaiter{};
    std::cout << "خطوة 2 بعد الاستئناف\n";
}

int main() {
    run();
}

